INSERT INTO snippets (category, trigger, content, disease)
VALUES 
('复诊', '/ysy_fz1', '牙髓炎治疗第一次复诊：患牙无自发痛及咬合痛，暂封完整，无脱落。局麻下去除暂封物，常规冲洗，探测根管口无渗出，无异味。使用机扩常规行根管预备，次氯酸钠及生理盐水交替冲洗，吸干，根管内封氢氧化钙糊剂，暂封。预约下次根充。', '牙髓炎'),
('复诊', '/ysy_fz2', '牙髓炎治疗第二次复诊：患牙封药期间无明显不适，暂封完好，叩诊(-)，无松动，牙龈无红肿。去暂封常规冲洗，吸干根管，试主牙胶尖，行X线片示充填长度及致密度良好。常规使用iRoot SP热牙胶行根管充填，暂封。预约下次行永久充填或冠修复。', '牙髓炎'),
('复诊', '/ysy_fz3', '牙髓炎根充后复诊：患牙根充后观察一周无不适。常规行根管纤维桩备置，试桩，黏贴纤维桩，利用树脂进行核成形。常规行全冠牙体预备（车牙），排龈，取模或数字化扫描，制作临时冠黏贴。预约下次试戴全冠。', '牙髓炎'),
('复诊', '/gjy_fz1', '根尖炎复诊：患牙无明显自发痛，颊侧龈窦道开口显著缩小，挤压无溢脓。常规去除暂封，使用次氯酸钠及生理盐水交替超声冲洗，探测根管内无明显渗出。封药氢氧化钙，暂封。窦道局部冲洗，涂碘甘油。', '根尖炎'),
('复诊', '/gjy_fz2', '根尖炎复诊：患牙无咬合痛。检查见颊侧窦道完全闭合，牙龈颜色正常，叩(-)。去除暂封常规吸干，根管内无渗出无异味。常规行根管热牙胶充填，拍摄X线片示恰填。暂封，嘱两周后复诊冠修复。', '根尖炎'),
('复诊', '/gjy_fz3', '根尖炎复诊：患牙偶有轻微咬合不适，叩诊轻度敏感(±)，根尖区牙龈轻度充血。去暂封，使用生理盐水彻底超声冲洗根管，吸干，更换封药（强效氢氧化钙糊剂），暂封。嘱继续观察。', '根尖炎'),
('复诊', '/gdy_fz1', '固定修复复诊：试戴全瓷冠/烤瓷桥。检查边缘密合度良好，邻接关系合适，无食物嵌塞。调磨咬合，抛光。常规使用3M树脂水门汀或玻璃离子黏固，去净多余黏结剂。嘱患者两周内勿咬过硬食物，定期复查。', '固定牙修复'),
('复诊', '/gdy_fz2', '固定修复初诊/复诊：患者要求行固定修复。常规行基牙牙体预备（备牙），排龈，使用硅橡胶取模或数字化口内扫描，记录咬合关系。制作临时冠黏贴，比色。预约一周后试戴正式冠。', '固定牙修复'),
('复诊', '/gdy_fz3', '固定修复戴冠后复查：患者主诉戴冠后偶有咬合不适或冷热轻度敏感。检查见冠边缘密合，龈乳头无明显红肿。使用咬合纸检查发现局部有早接触点，常规调磨、抛光，冷热刺激渐缓。嘱注意清洁。', '固定牙修复'),
('复诊', '/hdy_fz1', '活动修复复诊：试戴局部活动义齿。检查基托与粘膜密合，卡环就位良好且固位合适。常规调磨局部咬合，检查无明显组织压痛点。指导患者摘戴及清洁方法，嘱每晚泡在清水中，如有压痛及时复诊调磨。', '活动牙修复'),
('复诊', '/hdy_fz2', '活动义齿戴后复查：患者主诉戴义齿后局部粘膜疼痛。检查见基托下方相应粘膜区有局限性充血或溃疡。常规在基托对应部位进行调磨、缓冲，抛光。局部喷涂开喉剑，嘱暂不戴用等待溃疡愈合，定期复查。', '活动牙修复'),
('复诊', '/hdy_fz3', '活动义齿长期复查：患者主诉义齿逐渐松动、咀嚼效率降低。检查见基托与粘膜之间存在明显间隙，义齿固位力下降。常规对义齿组织面进行清洁，使用自凝树脂或软衬材料进行重衬（加垫），调整咬合。固位及稳定性显著改善。', '活动牙修复');
